class AStar:
    """
    A* pathfinding algorithm implementation.

    A* finds the shortest path between two nodes in a weighted graph by using
    a heuristic function to guide the search towards the goal.

    Attributes:
        graph (Graph): The graph to search.
        heuristic (callable): Heuristic function estimate(node, goal).
    """
    def __init__(self, graph, heuristic):
        self.graph = graph
        self.heuristic = heuristic

    def find_path(self, start, goal):
        """
        Find the shortest path from start to goal using A* algorithm.

        Args:
            start: Starting node.
            goal: Goal node.

        Returns:
            list: Path from start to goal as a list of nodes, or None if not found.
        """
        open_set = {start}
        came_from = {}

        g_score = {start: 0}
        f_score = {start: self.heuristic(start, goal)}

        while open_set:
            current = min(open_set, key=lambda node: f_score.get(node, float('inf')))

            if current == goal:
                return self._reconstruct_path(came_from, current)

            open_set.remove(current)

            for neighbor in self.graph.get_neighbors(current):
                tentative_g = g_score[current] + self.graph.distance(current, neighbor)

                if tentative_g < g_score.get(neighbor, float('inf')):
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g
                    f_score[neighbor] = tentative_g + self.heuristic(neighbor, goal)
                    if neighbor not in open_set:
                        open_set.add(neighbor)

        return None

    def _reconstruct_path(self, came_from, current):
        """Reconstruct the path from start to goal."""
        path = [current]
        while current in came_from:
            current = came_from[current]
            path.append(current)
        path.reverse()
        return path

